"""A point cloud transfer protocol compatible with PaintCloud.

See <https://gitlab.geo-sat.com/rnd/research/pointcloudannotator/-/tree/main/LibPaintCloud/src/App/Network?ref_type=heads>
"""

import struct
from dataclasses import dataclass, field
from enum import IntEnum
from typing import List

from typing_extensions import Self

PROTOCOL_SIGNATURE: int = 0xC10D
UInt8 = int
UInt16 = int
UInt32 = int


class DataType(IntEnum):  # UInt8
    PositionAsDouble = 0  # Position stored as 3 double values, 24 bytes
    PositionAsInteger = 1  # Position stored as 3 integer values, 12 bytes
    Intensity = 2  # Intensity stored as uint16 value
    Point0PackedAttributes = 3  # Point0 packed attributes(ReturnNumber, NumberOfReturns, ScanDirectionFlag, EdgeOfFlightLine), 1 byte
    Point6PackedAttributes = 4  # Point6 packed attributes(ReturnNumber, NumberOfReturns, ClassificationFlags, ScannerChannel, ScanDirectionFlag, EdgeOfFlightLine), 2 bytes
    Classification = 5  # Classification, 1 byte
    ScanAngleRank = 6  # Scan angle rank?, 1 byte
    ScanAngle = 7  # Scan angle?, 2 bytes
    UserData = 8  # User data, 1 byte
    PointSourceId = 9  # Point source Id, 2 bytes
    GpsTime = 10  # GPS time, 8 bytes
    Rgb = 11  # Red green blue data, 6 bytes
    Nir = 12  # Near infrared data, 2 bytes
    Waveform = 13  # Waveform data, 29 bytes
    ExtraData = 14  # Extra data, user defined size

    @staticmethod
    def size_in_bytes() -> int:
        return 1


class MessageType(IntEnum):  # UInt32
    Undefined = 0
    Command = 1
    PointArray = 2
    ConfigureJson = 3

    @staticmethod
    def size_in_bytes() -> int:
        return 4

    @classmethod
    def parse(cls, data: bytes) -> Self:
        return cls(struct.unpack_from("<I", data)[0])


class ProcessingType(IntEnum):  # UInt32
    NoneProcessing = 0
    Susann = 1
    Eclair = 2

    @staticmethod
    def size_in_bytes() -> int:
        return 4

    @classmethod
    def parse(cls, data: bytes) -> Self:
        return cls(struct.unpack_from("<I", data)[0])


@dataclass
class MessageHeader:
    size: UInt32 = 0  # Message size, excluding message header
    signature: UInt16 = PROTOCOL_SIGNATURE  # Protocol signature
    major_version: UInt8 = 0  # Protocol version major
    minor_version: UInt8 = 0  # Protocol version minor
    type_: MessageType = MessageType.Undefined  # Message type

    @staticmethod
    def size_in_bytes() -> int:
        return 12  # 4+2+1+1+4

    def tobytes(self) -> bytes:
        return struct.pack(
            "<IHBBI",
            self.size,
            self.signature,
            self.major_version,
            self.minor_version,
            self.type_,
        )

    @classmethod
    def parse(cls, data: bytes) -> Self:
        size, sig, maj_v, min_v, msg_type = struct.unpack_from("<IHBBI", data)
        if sig != PROTOCOL_SIGNATURE:
            raise ValueError("Invalid protocol signature")
        return cls(size, sig, maj_v, min_v, MessageType(msg_type))


@dataclass
class ElementDescriptor:
    type_: DataType
    size: UInt8

    @staticmethod
    def size_in_bytes() -> int:
        return 2

    @classmethod
    def parse(cls, data: bytes) -> Self:
        type_val, size = struct.unpack_from("<BB", data)
        return cls(DataType(type_val), size)


@dataclass
class PointStructure:
    # element_count: UInt16
    elements: List[ElementDescriptor] = field(default_factory=list)
    _size_of_element_count = 2

    @property
    def point_size(self) -> int:
        return sum(el.size for el in self.elements)

    @property
    def element_count(self) -> int:
        return len(self.elements)

    def size_in_bytes(self) -> int:
        return (
            ElementDescriptor.size_in_bytes() * len(self.elements)
            + self._size_of_element_count
        )

    @classmethod
    def parse(cls, data: bytes) -> Self:
        (element_count,) = struct.unpack_from("<H", data)
        offset = cls._size_of_element_count
        elements: List[ElementDescriptor] = []
        for _ in range(element_count):
            elements.append(ElementDescriptor.parse(data[offset:]))
            offset += ElementDescriptor.size_in_bytes()
        return cls(elements)


@dataclass
class ProcessCommand:
    type_: ProcessingType
    in_data_structure: PointStructure
    out_data_structure: PointStructure

    def size_in_bytes(self) -> int:
        return (
            self.type_.size_in_bytes()
            + self.in_data_structure.size_in_bytes()
            + self.out_data_structure.size_in_bytes()
        )

    @classmethod
    def parse(cls, data: bytes) -> Self:
        proc_type = ProcessingType.parse(data)
        offset = proc_type.size_in_bytes()
        in_data_structure = PointStructure.parse(data[offset:])
        offset += in_data_structure.size_in_bytes()
        out_data_structure = PointStructure.parse(data[offset:])
        return cls(proc_type, in_data_structure, out_data_structure)


@dataclass
class Message:
    header: MessageHeader
    body: bytes
